12→     * Constructor for a PySetObj; initializes its value to a list containing each
13→     * character in the input String.
14→     *
15→     * @param value the sequence of characters representing the value of this PySetObj
16→     */
17→    public PyStringObj(String value) {
18→        this.value = new ArrayList<>();
19→        for (int idx = 0; idx < value.length(); idx++) {
20→            this.value.add(new PyCharObj(value.charAt(idx)));
21→        }
22→    }
